    )
    values ('20260705000000', 'existing', '2d39faf2e97fcb49e2e37a2322164b034bf6c09d5a797e9b7b2d034d40acef1d')
    on conflict (version) do update
      set mode = excluded.mode,
          source_sha256 = excluded.source_sha256,
          applied_at = now();
    return;
  end if;

  if v_any_core_table_present then
