CREATE OR REPLACE VIEW "public"."v_part_stock" AS
 SELECT "ps"."part_id",
    "ps"."location_id",
    ("ps"."qty_on_hand" - "ps"."qty_reserved") AS "qty_available",
    "ps"."qty_on_hand",
    "ps"."qty_reserved"
   FROM "public"."part_stock" "ps";
$profixiq_stmt_0295$;

